using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private OrderService _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _sut = new OrderService();
    }

    // --- CreateOrder: happy-path ---

    [TestMethod]
    public void CreateOrder_WithValidInputs_ReturnsOrderWithCorrectCustomerId()
    {
        var items = MakeItems(("Widget", 10.00m, 2));

        var order = _sut.CreateOrder("cust-1", items);

        Assert.AreEqual("cust-1", order.CustomerId);
    }

    [TestMethod]
    public void CreateOrder_WithSingleItem_CalculatesTotalCorrectly()
    {
        var items = MakeItems(("Widget", 5.50m, 3));

        var order = _sut.CreateOrder("cust-1", items);

        Assert.AreEqual(16.50m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_WithMultipleItems_SumsTotalAcrossAllItems()
    {
        var items = MakeItems(
            ("Widget", 10.00m, 2),
            ("Gadget", 25.00m, 1));

        var order = _sut.CreateOrder("cust-1", items);

        Assert.AreEqual(45.00m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_AssignsNonEmptyId()
    {
        var items = MakeItems(("Widget", 1.00m, 1));

        var order = _sut.CreateOrder("cust-1", items);

        Assert.IsFalse(string.IsNullOrWhiteSpace(order.Id));
    }

    [TestMethod]
    public void CreateOrder_AssignsUniqueIds()
    {
        var items = MakeItems(("Widget", 1.00m, 1));

        var order1 = _sut.CreateOrder("cust-1", items);
        var order2 = _sut.CreateOrder("cust-1", items);

        Assert.AreNotEqual(order1.Id, order2.Id);
    }

    [TestMethod]
    public void CreateOrder_SetsCreatedAtToRecentUtcTime()
    {
        var before = DateTime.UtcNow;
        var items = MakeItems(("Widget", 1.00m, 1));

        var order = _sut.CreateOrder("cust-1", items);

        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= DateTime.UtcNow);
    }

    [TestMethod]
    public void CreateOrder_StoresItemsOnOrder()
    {
        var items = MakeItems(("Widget", 1.00m, 1), ("Gadget", 2.00m, 3));

        var order = _sut.CreateOrder("cust-1", items);

        Assert.AreEqual(2, order.Items.Count);
        Assert.AreEqual("Widget", order.Items[0].ProductName);
        Assert.AreEqual("Gadget", order.Items[1].ProductName);
    }

    // --- CreateOrder: validation ---

    [TestMethod]
    public void CreateOrder_WithNullCustomerId_ThrowsArgumentNullException()
    {
        var items = MakeItems(("Widget", 1.00m, 1));

        Assert.ThrowsException<ArgumentNullException>(() => _sut.CreateOrder(null!, items));
    }

    [TestMethod]
    public void CreateOrder_WithNullItems_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(() => _sut.CreateOrder("cust-1", null!));
    }

    [TestMethod]
    public void CreateOrder_WithEmptyItems_ThrowsInvalidOperationException()
    {
        Assert.ThrowsException<InvalidOperationException>(
            () => _sut.CreateOrder("cust-1", []));
    }

    // --- GetOrder ---

    [TestMethod]
    public void GetOrder_AfterCreation_ReturnsTheCreatedOrder()
    {
        var items = MakeItems(("Widget", 1.00m, 1));
        var created = _sut.CreateOrder("cust-1", items);

        var fetched = _sut.GetOrder(created.Id);

        Assert.IsNotNull(fetched);
        Assert.AreEqual(created.Id, fetched.Id);
    }

    [TestMethod]
    public void GetOrder_WithNonexistentId_ReturnsNull()
    {
        var result = _sut.GetOrder("does-not-exist");

        Assert.IsNull(result);
    }

    // --- GetOrdersByCustomer ---

    [TestMethod]
    public void GetOrdersByCustomer_ReturnsOnlyThatCustomersOrders()
    {
        var items = MakeItems(("Widget", 1.00m, 1));
        _sut.CreateOrder("cust-1", items);
        _sut.CreateOrder("cust-1", items);
        _sut.CreateOrder("cust-2", items);

        var result = _sut.GetOrdersByCustomer("cust-1");

        Assert.AreEqual(2, result.Count);
        Assert.IsTrue(result.All(o => o.CustomerId == "cust-1"));
    }

    [TestMethod]
    public void GetOrdersByCustomer_WhenNoneExist_ReturnsEmptyList()
    {
        var result = _sut.GetOrdersByCustomer("cust-unknown");

        Assert.AreEqual(0, result.Count);
    }

    [TestMethod]
    public void GetOrdersByCustomer_ReturnsReadOnlyList()
    {
        var items = MakeItems(("Widget", 1.00m, 1));
        _sut.CreateOrder("cust-1", items);

        var result = _sut.GetOrdersByCustomer("cust-1");

        Assert.IsInstanceOfType<IReadOnlyList<Order>>(result);
    }

    // --- helpers ---

    private static List<OrderItem> MakeItems(params (string Name, decimal Price, int Qty)[] specs) =>
        specs.Select(s => new OrderItem
        {
            ProductName = s.Name,
            Price = s.Price,
            Quantity = s.Qty
        }).ToList();
}

